import React, { useState, useEffect, useRef, useCallback } from 'react';

const images = [
  '/images/login%201.jpg',
  '/images/login%202.jpg',
  '/images/chat%20screen%201.jpg',
  '/images/outcoming%201.jpg',
  '/images/outcoming%202.jpg',
];

function TechGlobeSection() {
  const [currentImage, setCurrentImage] = useState(0);
  const [revealState, setRevealState] = useState('in');
  const [activeVideo, setActiveVideo] = useState(0);
  const [videoOpacity, setVideoOpacity] = useState(1);
  const video2Ref = useRef(null);

  // Image slideshow
  useEffect(() => {
    let timeout1, timeout2;
    const cycle = () => {
      setRevealState('in');
      timeout1 = setTimeout(() => {
        setRevealState('out');
        timeout2 = setTimeout(() => {
          setCurrentImage((prev) => (prev + 1) % images.length);
        }, 500);
      }, 2000);
    };
    cycle();
    const interval = setInterval(cycle, 2800);
    return () => {
      clearInterval(interval);
      clearTimeout(timeout1);
      clearTimeout(timeout2);
    };
  }, []);

  // Video 2 - stop at 4s
  const handleVideo2Time = useCallback(() => {
    const v = video2Ref.current;
    if (v && v.currentTime >= 4) {
      v.pause();
      setVideoOpacity(0);
      setTimeout(() => {
        setActiveVideo(0);
        setVideoOpacity(1);
      }, 500);
    }
  }, []);

  // Video 1 ended -> switch to video 2
  const handleVideo1End = useCallback(() => {
    setVideoOpacity(0);
    setTimeout(() => {
      setActiveVideo(1);
      setVideoOpacity(1);
      const v = video2Ref.current;
      if (v) {
        v.currentTime = 0;
        v.play().catch(() => {});
      }
    }, 500);
  }, []);

  return (
    <section className="relative py-20 px-4 sm:px-6 lg:px-8 overflow-hidden bg-white">
      <style>{`
        @keyframes revealOpen {
          from { clip-path: inset(50% 50% 50% 50% round 16px); }
          to { clip-path: inset(0% 0% 0% 0% round 16px); }
        }
        @keyframes revealClose {
          from { clip-path: inset(0% 0% 0% 0% round 16px); }
          to { clip-path: inset(50% 50% 50% 50% round 16px); }
        }
        .img-reveal-in { animation: revealOpen 0.6s ease-out forwards; }
        .img-reveal-out { animation: revealClose 0.4s ease-in forwards; }
      `}</style>

      <div className="relative max-w-6xl mx-auto">
        <div className="text-center mb-12">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">Sản Phẩm Của Chúng Tôi</h2>
          <p className="text-gray-500 text-lg">Xem demo trực tiếp sản phẩm đã triển khai</p>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 items-center justify-center">
          {/* Left - Video (landscape) */}
          <div className="w-full lg:w-3/5">
            <div 
              className="relative rounded-2xl overflow-hidden shadow-2xl"
              style={{ aspectRatio: '16/9', background: '#000', transition: 'opacity 0.5s', opacity: videoOpacity }}
            >
              {/* Video 1 - laptop */}
              <video
                className="absolute inset-0 w-full h-full object-cover"
                autoPlay
                muted
                playsInline
                onEnded={handleVideo1End}
                style={{ display: activeVideo === 0 ? 'block' : 'none' }}
                src="/videos/video%20laptop.mp4"
              />
              {/* Video 2 - send images (max 4s) */}
              <video
                ref={video2Ref}
                className="absolute inset-0 w-full h-full object-cover"
                muted
                playsInline
                onTimeUpdate={handleVideo2Time}
                style={{ display: activeVideo === 1 ? 'block' : 'none' }}
                src="/videos/send%20images.mp4"
              />
            </div>
          </div>

          {/* Right - Image slideshow (portrait) */}
          <div className="w-full lg:w-2/5 flex items-center justify-center">
            <div className="relative" style={{ width: '260px', height: '520px' }}>
              {images.map((src, index) => (
                index === currentImage && (
                  <div
                    key={`${index}-${currentImage}`}
                    className={revealState === 'in' ? 'img-reveal-in' : 'img-reveal-out'}
                    style={{ position: 'absolute', inset: 0 }}
                  >
                    <img
                      src={src}
                      alt={`Screenshot ${index + 1}`}
                      className="w-full h-full object-cover rounded-2xl shadow-lg"
                    />
                  </div>
                )
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default TechGlobeSection;
